-- ============================================================
-- RECETAS COMPLETAS: Perfumes terminados BOM (Bill of Materials)
-- Tenant: d46bec36-5259-4b5b-83c7-01f1e6ea5dcd (Perfum Mua)
-- 239 extractos x 3 presentaciones = 717 productos terminados
-- 2151 registros de recetas (3 ingredientes x 3 tamanos)
-- Ejecutar: mysql -u root -p stockpro_db < recetasperfummua.sql
-- NOTA: Requiere que inventario_perfummua.sql ya haya sido ejecutado
-- ============================================================

USE stockpro_db;

-- ============================================================
-- 1. TABLA DE RECETAS
-- ============================================================
CREATE TABLE IF NOT EXISTS product_recipes (
    id VARCHAR(36) PRIMARY KEY,
    tenant_id VARCHAR(36) NOT NULL,
    product_id VARCHAR(36) NOT NULL,
    ingredient_id VARCHAR(36) NOT NULL,
    quantity DECIMAL(10,3) NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE,
    FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
    FOREIGN KEY (ingredient_id) REFERENCES products(id) ON DELETE RESTRICT,
    INDEX idx_recipe_product (product_id),
    INDEX idx_recipe_tenant (tenant_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- 2. VARIABLES
-- ============================================================
SET @tid    = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd' COLLATE utf8mb4_unicode_ci;
SET @env30  = 'prod-pm-2002' COLLATE utf8mb4_unicode_ci; -- ENVASE LACOSTE 30ML  ($2,800 venta)
SET @env100 = 'prod-pm-2004' COLLATE utf8mb4_unicode_ci; -- ENVASE LACOSTE 100ML ($2,900 venta)
SET @caj30  = 'prod-pm-2005' COLLATE utf8mb4_unicode_ci; -- CAJA 30-50ML         ($1,800 venta)
SET @caj100 = 'prod-pm-2006' COLLATE utf8mb4_unicode_ci; -- CAJA 100ML           ($1,600 venta)
SET @env50  = 'prod-pm-2007' COLLATE utf8mb4_unicode_ci; -- ENVASE LACOSTE 50ML  ($2,900 venta)

-- ============================================================
-- 3. CATEGORIA PERFUMERIA (si no existe)
-- ============================================================

-- ============================================================
-- 4. LIMPIAR DATOS PREVIOS (idempotente)
-- ============================================================
DELETE FROM product_recipes WHERE tenant_id = @tid AND product_id LIKE 'PERF-%';
DELETE FROM products WHERE tenant_id = @tid AND id LIKE 'PERF-%';

-- ============================================================
-- 5. PRODUCTOS TERMINADOS 30ML
--    Costo BOM: 13*1700 + 2800 + 1800 = $26,700 (redondeado a $27,000)
--    Precio venta: $65,000
-- ============================================================

-- ============================================================
-- 6. PRODUCTOS TERMINADOS 50ML
--    Costo BOM: 22*1700 + 2900 + 1800 = $42,100 (redondeado a $42,000)
--    Precio venta: $90,000
-- ============================================================

-- ============================================================
-- 7. PRODUCTOS TERMINADOS 100ML
--    Costo BOM: 43*1700 + 2900 + 1600 = $77,600 (redondeado a $78,000)
--    Precio venta: $150,000
-- ============================================================

-- ============================================================
-- 8. RECETAS BOM
--    30ML  = 13 extracto + 1 envase 30ML  + 1 caja 30-50ML
--    50ML  = 22 extracto + 1 envase 50ML  + 1 caja 30-50ML
--    100ML = 43 extracto + 1 envase 100ML + 1 caja 100ML
-- ============================================================
-- Recetas extractos 1-88

-- Recetas extractos 89-177

-- Recetas extractos 178-239

-- ============================================================
-- 9. VERIFICACION
-- ============================================================
SELECT CONCAT('Productos terminados creados: ', COUNT(*)) AS resultado
FROM products WHERE tenant_id = @tid AND id LIKE 'PERF-%';

SELECT CONCAT('Recetas creadas: ', COUNT(*)) AS resultado
FROM product_recipes WHERE tenant_id = @tid AND product_id LIKE 'PERF-%';

SELECT
    p.name AS Perfume,
    p.presentation AS Presentacion,
    CONCAT('$', FORMAT(p.purchase_price, 0)) AS 'Costo BOM',
    CONCAT('$', FORMAT(p.sale_price, 0)) AS 'Precio Venta',
    CONCAT(ROUND((p.sale_price - p.purchase_price) / p.sale_price * 100, 1), '%') AS Margen,
    (SELECT FLOOR(MIN(CASE WHEN pr.quantity > 0 THEN ing.stock / pr.quantity ELSE 0 END))
     FROM product_recipes pr
     JOIN products ing ON ing.id = pr.ingredient_id
     WHERE pr.product_id = p.id) AS 'Stock Disponible BOM'
FROM products p
WHERE p.tenant_id = @tid AND p.id LIKE 'PERF-s1-001-%'
ORDER BY p.sale_price;

SELECT 'Seed ejecutado correctamente. Los perfumes apareceran en el POS con su receta BOM.' AS RESULTADO;